impl ChangeDetector for MseDetector {
    fn score(&self, pixels: &[u8]) -> f32 {
        match self.reference.as_ref() {
            Some(r) => frame_mse(pixels, r),
            None => f32::MAX,
        }
    }

    fn set_reference(&mut self, pixels: &[u8]) {
        self.reference = Some(pixels.to_vec());
    }

    fn reset(&mut self) {
        self.reference = None;
    }
}

